class Solution {
    public int latestTimeCatchTheBus(int[] buses, int[] passengers, int capacity) {
        Arrays.sort(buses);
        Arrays.sort(passengers);
        int[] waiting = new int[passengers.length];
        int j = 0;
        for (int i = 0; i < passengers.length; i++) {
            while (j < buses.length && buses[j] < passengers[i]) {
                j++;
            }
            if (j < buses.length) {
                waiting[i] = j;
            }
        }
        int res = -1;
        for (int i = 0; i < passengers.length; i++) {
            if (waiting[i] == 0) {
                continue;
            }
            int count = 0;
            for (int k = i; k >= 0; k--) {
                if (waiting[k] == waiting[i]) {
                    count++;
                } else {
                    break;
                }
            }
            if (count < capacity) {
                res = Math.max(res, buses[waiting[i] - 1]);
            }
        }
        if (res == -1) {
            return passengers[passengers.length - 1];
        }
        for (int i = passengers.length - 1; i >= 0; i--) {
            if (waiting[i] == waiting[passengers.length - 1]) {
                res = Math.max(res, passengers[i] - 1);
            } else {
                break;
            }
        }
        return res;
    }
}
